Use **`WebApplicationFactory<TEntryPoint>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your app in-memory and gives you an `HttpClient` — no ports, no real server.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
```

### Test fixture

```csharp
public class McpTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        // Send MCP initialize request
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                clientInfo = new { name = "test-client", version = "1.0" },
                capabilities = new { }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_AfterInit_ReturnsTools()
    {
        // Initialize first
        await _client.PostAsJsonAsync("/mcp", new
        {
            jsonrpc = "2.0", id = 1, method = "initialize",
            @params = new { protocolVersion = "2025-03-26",
                clientInfo = new { name = "test", version = "1.0" },
                capabilities = new { } }
        });

        // Then list tools
        var response = await _client.PostAsJsonAsync("/mcp", new
        {
            jsonrpc = "2.0", id = 2, method = "tools/list",
            @params = new { }
        });

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.True(body.GetProperty("result").TryGetProperty("tools", out var tools));
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

### Key points

- **`WebApplicationFactory<Program>`** boots your real `Program` startup pipeline (DI, middleware, routing) in-process — zero network overhead.
- Override services via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in fakes (e.g., mock databases).
- If your MCP endpoint uses **SSE (Streamable HTTP)**, read the response stream with `HttpCompletionOption.ResponseHeadersRead` and parse `text/event-stream` lines.
- Make sure `Program` is visible to the test project (add `InternalsVisibleTo` or a partial `public class Program { }` declaration).

### Testing SSE streams

```csharp
var request = new HttpRequestMessage(HttpMethod.Post, "/mcp");
request.Content = JsonContent.Create(new { jsonrpc = "2.0", id = 1, method = "initialize", ... });
request.Headers.Accept.Add(new("text/event-stream"));

var response = await _client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);
using var stream = await response.Content.ReadAsStreamAsync();
using var reader = new StreamReader(stream);

while (await reader.ReadLineAsync() is { } line)
{
    if (line.StartsWith("data: "))
    {
        var json = JsonDocument.Parse(line[6..]);
        // assert on each SSE event
    }
}
```

This gives you full protocol-level coverage with the real middleware pipeline, all running in-process.
